noncompliant:
switch (value = readInput()) {
    case 1: break;
    default: break;
}

compliant:
count = getCount();
while (count) {
    process(count);
    count = getCount();
}

while ((run = keepRunning())) {
    // Allowed: explicitly enclosed in parentheses
    doWork();
}

if (x == getValue()) {
    // Equality comparison, not assignment
    doSomething();
}

value = readInput();
switch (value) {
    case 1: break;
    default: break;
}
